class Solution:
    def ladderLength(self, beginWord, endWord, wordList):
        from collections import deque
        words = set(wordList)
        if endWord not in words:
            return 0
        L = len(beginWord)
        def neighbours(w):
            for i in range(L):
                for c in 'abcdefghijklmnopqrstuvwxyz':
                    if c != w[i]:
                        cand = w[:i] + c + w[i+1:]
                        if cand in words:
                            yield cand
        q = deque([(beginWord, 1)])
        visited = {beginWord}
        while q:
            w, d = q.popleft()
            if w == endWord:
                return d
            for nb in neighbours(w):
                if nb not in visited:
                    visited.add(nb)
                    q.append((nb, d + 1))
        return 0

