class Solution:
    def ladderLength(self, beginWord, endWord, wordList):
        from collections import deque
        words = set(wordList)
        if endWord not in words:
            return 0
        L = len(beginWord)
        q = deque([beginWord])
        visited = {beginWord}
        level = 1
        while q:
            for _ in range(len(q)):
                w = q.popleft()
                if w == endWord:
                    return level
                for i in range(L):
                    for c in 'abcdefghijklmnopqrstuvwxyz':
                        if c == w[i]:
                            continue
                        cand = w[:i] + c + w[i+1:]
                        if cand in words and cand not in visited:
                            visited.add(cand)
                            q.append(cand)
            level += 1
        return 0

