var ladderLength = function(beginWord, endWord, wordList) {
    const words = new Set(wordList);
    if (!words.has(endWord)) return 0;
    const L = beginWord.length;
    let q = [beginWord];
    const visited = new Set([beginWord]);
    let level = 1;
    while (q.length) {
        const next = [];
        for (const w of q) {
            if (w === endWord) return level;
            for (let i = 0; i < L; i++) {
                for (let cc = 97; cc < 123; cc++) {
                    const c = String.fromCharCode(cc);
                    if (c === w[i]) continue;
                    const cand = w.slice(0, i) + c + w.slice(i + 1);
                    if (words.has(cand) && !visited.has(cand)) {
                        visited.add(cand);
                        next.push(cand);
                    }
                }
            }
        }
        q = next;
        level += 1;
    }
    return 0;
};
